def maxval(xs):
    m = xs[0]
    for x in xs:
        if x > m:
            m = x
    return m

setup_files.paren.py:
def is_balanced(s):
    n = 0
    for c in s:
        if c in '([{':
            n += 1
        elif c in ')]}':
            n -= 1
        if n < 0:
            return False
    return n == 0
